"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useState } from "react";

const navLinks = [
  { href: "/", label: "Início" },
  { href: "/cv", label: "Experiência" },
  { href: "/stack", label: "Stack" },
  { href: "/publications", label: "Publicações" },
  { href: "/blog", label: "Blog" },
];

export default function Navbar() {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const pathname = usePathname();

  return (
    <header className="border-b border-gray-100 bg-white/70 backdrop-blur-xl sticky top-0 z-50">
      <div className="flex items-center justify-between px-6 md:px-20 py-4 md:py-6">
        <div className="flex items-center gap-3">
          <div className="size-9 bg-content-dark rounded-xl flex items-center justify-center text-white">
            <span className="material-symbols-outlined text-lg">terminal</span>
          </div>
          <h2 className="text-content-dark text-xl font-black tracking-tight">Schardosim</h2>
        </div>

        <div className="hidden md:flex flex-1 justify-end gap-12 items-center">
          <nav className="flex items-center gap-10">
            {navLinks.map((link) => {
              const isActive = pathname === link.href;
              return (
                <Link
                  key={link.href}
                  href={link.href}
                  className={`transition-colors text-sm font-semibold tracking-wide ${
                    isActive
                      ? "text-primary font-bold"
                      : "text-content-muted hover:text-primary"
                  }`}
                >
                  {link.label}
                </Link>
              );
            })}
          </nav>
          <button className="bg-content-dark hover:bg-black text-white px-7 py-2.5 rounded-full text-sm font-bold transition-all flex items-center gap-2">
            Currículo
            <span className="material-symbols-outlined" style={{ fontSize: "12pt" }}>
              description
            </span>
          </button>
        </div>

        <button
          className="md:hidden p-2 rounded-lg text-content-dark hover:bg-gray-100 transition-colors"
          onClick={() => setIsMenuOpen((prev) => !prev)}
          aria-label={isMenuOpen ? "Fechar menu" : "Abrir menu"}
          title={isMenuOpen ? "Fechar menu" : "Abrir menu"}
        >
          <span className="material-symbols-outlined">{isMenuOpen ? "close" : "menu"}</span>
        </button>
      </div>

      {isMenuOpen && (
        <div className="md:hidden px-6 pb-5 border-t border-gray-100 bg-white/95">
          <nav className="flex flex-col gap-3 pt-4">
            {navLinks.map((link) => {
              const isActive = pathname === link.href;
              return (
                <Link
                  key={link.href}
                  href={link.href}
                  className={`transition-colors text-sm font-semibold tracking-wide py-1 ${
                    isActive
                      ? "text-primary font-bold"
                      : "text-content-muted hover:text-primary"
                  }`}
                  onClick={() => setIsMenuOpen(false)}
                >
                  {link.label}
                </Link>
              );
            })}
          </nav>
          <button className="mt-2 ml-auto max-w-fit bg-content-dark hover:bg-black text-white px-5 py-2.5 rounded-full text-sm font-bold transition-all flex items-center justify-center gap-2">
            Currículo
            <span className="material-symbols-outlined" style={{ fontSize: "10pt" }}>
              description
            </span>
          </button>
        </div>
      )}
    </header>
  );
}
